"use client";
import { kycScheme } from "@/lib/validations";
import { zodResolver } from "@hookform/resolvers/zod";
import { redirect, useRouter } from "next/navigation";
import React, { useState } from "react";
import { useForm } from "react-hook-form";
import z from "zod";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "../ui/form";

import { RadioGroup, RadioGroupItem } from "../ui/radio-group";
import { cn } from "@/lib/utils";
import { IkycFormFields } from "@/lib/dummyData";
import Link from "next/link";
import { useNeedReceiptStore, useUserDataStore } from "@/store/userStore";

const KycForm = () => {
  const form = useForm<z.infer<typeof kycScheme>>({
    resolver: zodResolver(kycScheme),
    defaultValues: {
      firstName: "",
      lastName: "",
    },
  });
  const onSubmit = (values: z.infer<typeof kycScheme>) => {
    console.log(values);
    // const result = await addProducts(values);
  };

  const { firstName, lastName, setFirstName, setLastName, saveData, newData } =
    useUserDataStore();

  const status = useNeedReceiptStore((state) => state.receiptStatus);

  return status === "No" ? (
    redirect("/")
  ) : (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(onSubmit)}
        className="bg-[#f7f5dc] shadow-md rounded px-8 pt-6 pb-8 mb-4"
        method="POST"
      >
        <p className="md:text-2xl lg:text-3xl py-4">
          Let's Verify Your Account
        </p>
        <FormField
          control={form.control}
          name="firstName"
          render={({ field }) => (
            <FormItem className="mb-4">
              <FormLabel className="sm:text-md md:text-lg lg:text-xl">
                Select your ID
              </FormLabel>
              <FormControl>
                <RadioGroup
                  onValueChange={setFirstName}
                  defaultValue={field.value}
                  className="flex flex-col"
                >
                  <FormLabel
                    htmlFor={firstName}
                    className={cn(
                      "w-full flex items-center gap-3 rounded-lg border-2 p-3 cursor-pointer"
                    )}
                  >
                    <FormItem key={data.id}>
                      <FormControl key={data.id}>
                        <RadioGroupItem
                          value={data.value}
                          id={data.id}
                          key={data.id}
                        />
                      </FormControl>
                    </FormItem>
                    {data.label}
                  </FormLabel>
                </RadioGroup>
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        ></FormField>
        <Link
          onClick={() => saveData(datas)}
          rel="preload"
          href={"/cart"}
          className="py-2 px-4 rounded-md cursor-pointer text-white bg-[#216c58]"
        >
          Next
        </Link>
        {/* <Button type="submit" className="w-full cursor-pointer">
          NEXT
        </Button> */}
      </form>
    </Form>
  );
};

export default KycForm;
